using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 5.0);
    if (!circle)
        return false;

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the body created by the extrusion
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);
    if (!body)
        return false;

    // Create a scale input
    Ptr inputColl = ObjectCollection::create();
    if (!inputColl)
        return false;
    inputColl->add(body);

    Ptr sketchPts = sketch->sketchPoints();
    if (!sketchPts)
        return false;
    Ptr basePt = sketchPts->item(0);
    if (!basePt)
        return false;
    Ptr scaleFactor = ValueInput::createByReal(2);
    if (!scaleFactor)
        return false;
    Ptr scales = feats->scaleFeatures();
    if (!scales)
        return false;
    Ptr scaleInput = scales->createInput(inputColl, basePt, scaleFactor);
    if (!scaleInput)
        return false;

    // Set the scale to be non-uniform
    Ptr xScale = ValueInput::createByReal(1.5);
    if (!xScale)
        return false;
    Ptr yScale = ValueInput::createByReal(3);
    if (!yScale)
        return false;
    Ptr zScale = ValueInput::createByReal(2);
    if (!zScale)
        return false;
    scaleInput->setToNonUniform(xScale, yScale, zScale);

    Ptr scale = scales->add(scaleInput);
    if (!scale)
        return false;

    // Create another sketch
    Ptr yz = rootComp->yZConstructionPlane();
    if (!yz)
        return false;
    Ptr sketchVertical = sketches->add(yz);
    if (!sketchVertical)
        return false;
    Ptr sketchCurvesVertical = sketchVertical->sketchCurves();
    if (!sketchCurvesVertical)
        return false;
    Ptr sketchCirclesVertical = sketchCurvesVertical->sketchCircles();
    if (!sketchCirclesVertical)
        return false;
    Ptr centerPointVertical = Point3D::create(0, 10, 0);
    if (!centerPointVertical)
        return false;
    Ptr cicleVertical = sketchCirclesVertical->addByCenterRadius(centerPointVertical, 5);
    if (!cicleVertical)
        return false;

    // Create an uniformed input for scale feature input
    Ptr inputUniformColl = ObjectCollection::create();
    if (!inputUniformColl)
        return false;
    inputUniformColl->add(sketchVertical);

    Ptr scaleUniformInput = scales->createInput(inputUniformColl, basePt, scaleFactor);
    if (!scaleUniformInput)
        return false;

    Ptr scaleUniform = scales->add(scaleUniformInput);
    if (!scaleUniform)
        return false;

    return true;
}
